// Tree entry for building (internal)
struct TreeBuildEntry {
    char name[256];          // Entry name (filename only, not path)
    uint32_t mode;           // File mode
    char sha[Git::SHA1_HEX_SIZE + 1];  // SHA-1 hex
};

// Write a single tree object from entries
// Entries must have only the filename (no path components)
static bool write_tree_object(GitRepository* repo, TreeBuildEntry* entries,
                               size_t count, char* out_sha) {
    if (!repo || !entries || count == 0 || !out_sha) return false;

    // Calculate buffer size for tree content
    // Format: repeated (mode SP name NUL sha20)
    size_t buf_size = 0;
    for (size_t i = 0; i < count; i++) {
        char mode_str[16];
        snprintf(mode_str, sizeof(mode_str), "%o", entries[i].mode);
        buf_size += strlen(mode_str) + 1 + strlen(entries[i].name) + 1 + 20;
    }

    uint8_t* buffer = new uint8_t[buf_size];
    uint8_t* ptr = buffer;

    for (size_t i = 0; i < count; i++) {
        // Write mode (octal, no leading zeros except for single digit)
        char mode_str[16];
        snprintf(mode_str, sizeof(mode_str), "%o", entries[i].mode);
        size_t mode_len = strlen(mode_str);
        memcpy(ptr, mode_str, mode_len);
        ptr += mode_len;

        // Space separator
        *ptr++ = ' ';

        // Write name
        size_t name_len = strlen(entries[i].name);
        memcpy(ptr, entries[i].name, name_len);
        ptr += name_len;

        // Null separator
        *ptr++ = '\0';

        // Write SHA (raw 20 bytes)
        uint8_t sha_raw[20];
        hex_to_sha(entries[i].sha, sha_raw);
        memcpy(ptr, sha_raw, 20);
        ptr += 20;
    }

    // Write tree object
    size_t content_size = ptr - buffer;
    bool success = git_write_object(repo, GitObjectType::Tree, buffer, content_size, out_sha);

    delete[] buffer;
    return success;
}

// Compare function for sorting tree entries (git uses byte order)
static int compare_tree_entries(const void* a, const void* b) {
    const TreeBuildEntry* ea = static_cast<const TreeBuildEntry*>(a);
    const TreeBuildEntry* eb = static_cast<const TreeBuildEntry*>(b);

    // Git sorts tree entries by treating directories as if they end with '/'
    // This means "foo" (tree) comes before "foo.txt" (blob)
    char name_a[258], name_b[258];
    strcpy_s(name_a, ea->name);
    strcpy_s(name_b, eb->name);

    if (ea->mode == Git::MODE_TREE) strcat_s(name_a, "/");
    if (eb->mode == Git::MODE_TREE) strcat_s(name_b, "/");

    return strcmp(name_a, name_b);
}

// Recursive tree building helper.
// Processes entries[start..end) which all start with 'prefix' (a directory path,
// without trailing slash) and builds the corresponding tree object.
// The index is sorted by path, so:
//   - Entries with the same parent prefix are CONTIGUOUS.
//   - Entries belonging to the same subdirectory under prefix are also contiguous.
// This lets us skip the previous O(N * depth) full-array rescan and the
// processed_dirs[256] linear dedup; we just walk the slice once and recurse on
// contiguous subranges.
static bool build_tree_recursive_range(GitRepository* repo,
                                       GitIndexEntryFull* entries,
                                       size_t start, size_t end,
                                       const char* prefix, size_t prefix_len,
                                       char* out_sha) {
    // Worst-case allocation: every entry contributes one level entry (all files,
    // no subdirs). Subdirs only collapse this; never grow.
    size_t slice = end - start;
    TreeBuildEntry* level_entries = new TreeBuildEntry[slice > 0 ? slice : 1];
    size_t level_count = 0;

    size_t i = start;
    while (i < end) {
        const char* path = entries[i].path;
        const char* rel = (prefix_len > 0) ? path + prefix_len + 1 : path;
        const char* slash = strchr(rel, '/');

        if (slash == nullptr) {
            // File at this level.
            TreeBuildEntry* te = &level_entries[level_count++];
            strncpy_s(te->name, rel, sizeof(te->name) - 1);
            te->mode = entries[i].mode;
            strcpy_s(te->sha, entries[i].sha);
            i++;
        } else {
            // Subdirectory. Because entries are sorted, all entries that share
            // this subdirectory prefix form a contiguous range starting at i.
            size_t dir_len = slash - rel;
            char dir_name[256];
            if (dir_len >= sizeof(dir_name)) dir_len = sizeof(dir_name) - 1;
            memcpy(dir_name, rel, dir_len);
            dir_name[dir_len] = '\0';

            char subdir_prefix[Git::MAX_PATH_LEN];
            size_t subdir_prefix_len;
            if (prefix_len > 0) {
                int n = snprintf(subdir_prefix, sizeof(subdir_prefix), "%s/%s", prefix, dir_name);
                subdir_prefix_len = (n > 0) ? (size_t)n : 0;
            } else {
                memcpy(subdir_prefix, dir_name, dir_len);
                subdir_prefix[dir_len] = '\0';
                subdir_prefix_len = dir_len;
            }

            // Advance j over all entries that begin with subdir_prefix + '/'.
            size_t j = i + 1;
            while (j < end) {
                const char* p = entries[j].path;
                if (strncmp(p, subdir_prefix, subdir_prefix_len) != 0) break;
                if (p[subdir_prefix_len] != '/') break;
                j++;
            }

            char subtree_sha[Git::SHA1_HEX_SIZE + 1];
            if (!build_tree_recursive_range(repo, entries, i, j,
                                           subdir_prefix, subdir_prefix_len,
                                           subtree_sha)) {
                // Must fail the whole write-tree: silently omitting a subtree
                // produces a wrong root tree (missing files) while returning success.
                delete[] level_entries;
                return false;
            }
            TreeBuildEntry* te = &level_entries[level_count++];
            strcpy_s(te->name, dir_name);
            te->mode = Git::MODE_TREE;
            strcpy_s(te->sha, subtree_sha);
            i = j;
        }
    }

    // Sort entries (git requires sorted tree entries)
    if (level_count > 1) {
        qsort(level_entries, level_count, sizeof(TreeBuildEntry), compare_tree_entries);
    }

    // Write tree object
    bool success = false;
    if (level_count > 0) {
        success = write_tree_object(repo, level_entries, level_count, out_sha);
    }

    delete[] level_entries;
    return success;
}

// Build tree from current index
// Returns: true on success, fills out_tree_sha with root tree SHA
bool git_write_tree_from_index(GitRepository* repo, char* out_tree_sha) {
    if (!repo || !repo->is_valid || !out_tree_sha) return false;

    // Open index
    GitIndexFull index = {};
    if (!git_index_open_full(repo, &index)) {
        return false;
    }

    if (index.entry_count == 0) {
        git_index_close_full(&index);
        return false;  // Empty tree not allowed
    }

    // Git refuses write-tree when the index has unmerged (stage != 0) entries.
    for (size_t i = 0; i < index.entry_count; i++) {
        if (index.entries[i].stage != 0) {
            LOG("git_write_tree_from_index: unmerged stages present (path=%s stage=%u)",
                index.entries[i].path, index.entries[i].stage);
            git_index_close_full(&index);
            return false;
        }
    }

    // Sort index by path then stage (required for tree building)
    if (index.entry_count > 1) {
        qsort(index.entries, index.entry_count, sizeof(GitIndexEntryFull), compare_paths_full);
    }

    // Build tree recursively from root
    bool success = build_tree_recursive_range(repo, index.entries, 0, index.entry_count,
                                              "", 0, out_tree_sha);

    git_index_close_full(&index);
    return success;
}

