// Parse a git config file and extract user.name and user.email
static void parse_git_config(const char* content, GitConfig* config) {
    if (!content || !config) return;

    const char* ptr = content;
    bool in_user_section = false;
    bool in_core_section = false;

    while (*ptr) {
        // Skip whitespace
        while (*ptr == ' ' || *ptr == '\t') ptr++;

        // Check for section header
        if (*ptr == '[') {
            ptr++;
            // Check if this is [user] or [core] section
            in_user_section = (strncmp(ptr, "user]", 5) == 0 ||
                               strncmp(ptr, "user ", 5) == 0);  // [user "subsection"]
            in_core_section = (strncmp(ptr, "core]", 5) == 0 ||
                               strncmp(ptr, "core ", 5) == 0);  // [core "subsection"]
            // Skip to end of line
            while (*ptr && *ptr != '\n') ptr++;
            if (*ptr == '\n') ptr++;
            continue;
        }

        // Skip comments
        if (*ptr == '#' || *ptr == ';') {
            while (*ptr && *ptr != '\n') ptr++;
            if (*ptr == '\n') ptr++;
            continue;
        }

        // Skip empty lines
        if (*ptr == '\n' || *ptr == '\r') {
            ptr++;
            continue;
        }

        // Parse key=value
        if (in_user_section || in_core_section) {
            // Find key
            const char* key_start = ptr;
            while (*ptr && *ptr != '=' && *ptr != ' ' && *ptr != '\t' && *ptr != '\n') ptr++;
            size_t key_len = ptr - key_start;

            // Skip whitespace and =
            while (*ptr == ' ' || *ptr == '\t') ptr++;
            if (*ptr == '=') ptr++;
            while (*ptr == ' ' || *ptr == '\t') ptr++;

            // Find value (skip quotes if present)
            const char* val_start = ptr;
            if (*ptr == '"') {
                ptr++;  // Skip opening quote
                val_start = ptr;
                while (*ptr && *ptr != '"') ptr++;
                size_t val_len = ptr - val_start;
                if (*ptr == '"') ptr++;  // Skip closing quote

                // Process quoted value
                if (in_core_section) {
                    if (key_len == 8 && strncmp(key_start, "autocrlf", 8) == 0) {
                        if (val_len == 4 && strncmp(val_start, "true", 4) == 0) {
                            config->core_autocrlf = GitConfig::AutoCRLF::True;
                        } else if (val_len == 5 && strncmp(val_start, "false", 5) == 0) {
                            config->core_autocrlf = GitConfig::AutoCRLF::False;
                        } else if (val_len == 5 && strncmp(val_start, "input", 5) == 0) {
                            config->core_autocrlf = GitConfig::AutoCRLF::Input;
                        }
                    }
                }
            } else {
                // Unquoted value
                while (*ptr && *ptr != '\n' && *ptr != '\r' && *ptr != '#') ptr++;
                size_t val_len = ptr - val_start;

                // Trim trailing whitespace from value
                while (val_len > 0 && (val_start[val_len - 1] == ' ' ||
                                        val_start[val_len - 1] == '\t')) {
                    val_len--;
                }

                if (in_user_section) {
                    // Check for name or email
                    if (key_len == 4 && strncmp(key_start, "name", 4) == 0) {
                        if (val_len >= sizeof(config->user_name)) {
                            val_len = sizeof(config->user_name) - 1;
                        }
                        memcpy(config->user_name, val_start, val_len);
                        config->user_name[val_len] = '\0';
                    } else if (key_len == 5 && strncmp(key_start, "email", 5) == 0) {
                        if (val_len >= sizeof(config->user_email)) {
                            val_len = sizeof(config->user_email) - 1;
                        }
                        memcpy(config->user_email, val_start, val_len);
                        config->user_email[val_len] = '\0';
                    }
                } else if (in_core_section) {
                    // Parse core section values
                    if (key_len == 8 && strncmp(key_start, "autocrlf", 8) == 0) {
                        if (val_len == 4 && strncmp(val_start, "true", 4) == 0) {
                            config->core_autocrlf = GitConfig::AutoCRLF::True;
                        } else if (val_len == 5 && strncmp(val_start, "false", 5) == 0) {
                            config->core_autocrlf = GitConfig::AutoCRLF::False;
                        } else if (val_len == 5 && strncmp(val_start, "input", 5) == 0) {
                            config->core_autocrlf = GitConfig::AutoCRLF::Input;
                        }
                    }
                }
            }
        }

        // Skip to end of line
        while (*ptr && *ptr != '\n') ptr++;
        if (*ptr == '\n') ptr++;
    }
}

// Load git config (system, global, local - in order of increasing precedence)
bool git_config_load(GitRepository* repo, GitConfig* config) {
    if (!config) return false;

    memset(config, 0, sizeof(GitConfig));

    // Set safe defaults BEFORE parsing
    config->core_autocrlf = GitConfig::AutoCRLF::False;  // Safest default
    config->config_loaded = false;

    // First, load system config (C:\Program Files\Git\etc\gitconfig on Windows)
    wchar_t system_config_path[Git::MAX_PATH_LEN];
    if (GetEnvironmentVariableW(L"PROGRAMFILES", system_config_path, Git::MAX_PATH_LEN) > 0) {
        wcscat_s(system_config_path, L"\\Git\\etc\\gitconfig");

        char content[16384];
        size_t bytes_read = read_file(system_config_path, content, sizeof(content));
        if (bytes_read > 0) {
            parse_git_config(content, config);
            LOG("Loaded system config from: %ls", system_config_path);
        }
    }

    // Second, load global config (~/.gitconfig or %USERPROFILE%\.gitconfig)
    wchar_t home_path[Git::MAX_PATH_LEN];
    if (GetEnvironmentVariableW(L"USERPROFILE", home_path, Git::MAX_PATH_LEN) > 0) {
        wchar_t global_config_path[Git::MAX_PATH_LEN];
        wcscpy_s(global_config_path, home_path);
        wcscat_s(global_config_path, L"\\.gitconfig");

        char content[16384];
        size_t bytes_read = read_file(global_config_path, content, sizeof(content));
        if (bytes_read > 0) {
            parse_git_config(content, config);
        }
    }

    // Third, load local config (.git/config) which overrides global and system
    if (repo && repo->is_valid) {
        wchar_t git_dir_wide[Git::MAX_PATH_LEN];
        utf8_to_wide_n(repo->git_dir, git_dir_wide, Git::MAX_PATH_LEN);

        wchar_t local_config_path[Git::MAX_PATH_LEN];
        wcscpy_s(local_config_path, git_dir_wide);
        wcscat_s(local_config_path, L"\\config");

        char content[16384];
        size_t bytes_read = read_file(local_config_path, content, sizeof(content));
        if (bytes_read > 0) {
            parse_git_config(content, config);
        }
    }

    // Mark config as successfully loaded
    config->config_loaded = true;

    // Return true if we have both name and email (for commit operations)
    return (config->user_name[0] != '\0' && config->user_email[0] != '\0');
}

