// Forward declaration: defined below.
bool git_commit_create_multi(GitRepository* repo, const char* tree_sha,
                             const char** parent_shas, size_t parent_count,
                             const char* author_name, const char* author_email,
                             const char* committer_name, const char* committer_email,
                             const char* message, char* out_commit_sha);

// Create a commit object
// parent_sha can be nullptr or empty for initial commit
// Returns: true on success, fills out_commit_sha with commit SHA
bool git_commit_create(GitRepository* repo, const char* tree_sha, const char* parent_sha,
                       const char* author_name, const char* author_email,
                       const char* committer_name, const char* committer_email,
                       const char* message, char* out_commit_sha) {
    const char* parents[1] = { parent_sha };
    size_t parent_count = (parent_sha && parent_sha[0] != '\0') ? 1u : 0u;
    return git_commit_create_multi(repo, tree_sha, parents, parent_count,
                                   author_name, author_email,
                                   committer_name, committer_email,
                                   message, out_commit_sha);
}

// Create a commit with multiple parents (for stash W commits, merges, etc.)
// parent_shas is array of parent SHA strings, parent_count is number of parents (0-8)
// Returns: true on success, fills out_commit_sha with commit SHA
bool git_commit_create_multi(GitRepository* repo, const char* tree_sha,
                             const char** parent_shas, size_t parent_count,
                             const char* author_name, const char* author_email,
                             const char* committer_name, const char* committer_email,
                             const char* message, char* out_commit_sha) {
    if (!repo || !repo->is_valid || !tree_sha || !message || !out_commit_sha) return false;
    if (!author_name || !author_email || !committer_name || !committer_email) return false;
    if (parent_count > 0 && !parent_shas) return false;
    if (parent_count > 8) {
        LOG_WARN("git_commit_create_multi: parent_count %zu exceeds 8", parent_count);
        return false;
    }

    // Get current Unix timestamp
    int64_t now = static_cast<int64_t>(time(nullptr));

    // Get timezone offset
    TIME_ZONE_INFORMATION tz_info;
    DWORD tz_result = GetTimeZoneInformation(&tz_info);
    int tz_offset_minutes = -static_cast<int>(tz_info.Bias);
    if (tz_result == TIME_ZONE_ID_DAYLIGHT) {
        tz_offset_minutes -= static_cast<int>(tz_info.DaylightBias);
    }

    // Format timezone as +/-HHMM
    char tz_str[8];
    int tz_hours = abs(tz_offset_minutes) / 60;
    int tz_mins = abs(tz_offset_minutes) % 60;
    snprintf(tz_str, sizeof(tz_str), "%c%02d%02d",
             (tz_offset_minutes >= 0) ? '+' : '-', tz_hours, tz_mins);

    // Build commit content
    char content[Git::MAX_COMMIT_MSG + 2048];
    char* ptr = content;
    size_t remaining = sizeof(content);

    #define APPEND_FMT(...) do { \
        int _w = snprintf(ptr, remaining, __VA_ARGS__); \
        if (_w < 0 || static_cast<size_t>(_w) >= remaining) return false; \
        ptr += _w; remaining -= static_cast<size_t>(_w); \
    } while (0)

    // tree <sha>
    APPEND_FMT("tree %s\n", tree_sha);

    // parent <sha> lines (can have multiple)
    for (size_t i = 0; i < parent_count; i++) {
        if (parent_shas[i] && parent_shas[i][0] != '\0') {
            APPEND_FMT("parent %s\n", parent_shas[i]);
        }
    }

    // author <name> <email> <timestamp> <timezone>
    APPEND_FMT("author %s <%s> %lld %s\n",
               author_name, author_email, (long long)now, tz_str);

    // committer <name> <email> <timestamp> <timezone>
    APPEND_FMT("committer %s <%s> %lld %s\n",
               committer_name, committer_email, (long long)now, tz_str);

    if (remaining < 2) return false;

    // Blank line before message
    *ptr++ = '\n'; remaining--;

    // Message
    size_t msg_len = strlen(message);
    if (msg_len >= remaining) msg_len = remaining - 1;
    memcpy(ptr, message, msg_len);
    ptr += msg_len;
    remaining -= msg_len;

    // Ensure message ends with newline
    if (msg_len > 0 && *(ptr - 1) != '\n') {
        if (remaining < 1) return false;
        *ptr++ = '\n';
    }

    #undef APPEND_FMT

    size_t content_size = ptr - content;

    // Write commit object
    return git_write_object(repo, GitObjectType::Commit, content, content_size, out_commit_sha);
}

// Update a reference to point to a new SHA
bool git_ref_update(GitRepository* repo, const char* ref_name, const char* sha) {
    if (!repo || !repo->is_valid || !ref_name || !sha) return false;

    // Containment: only HEAD or refs/*; reject path escape and Windows separators
    if (strcmp(ref_name, "HEAD") != 0) {
        if (strncmp(ref_name, "refs/", 5) != 0) return false;
        if (strstr(ref_name, "..") != nullptr) return false;
        if (strchr(ref_name, '\\') != nullptr) return false;
        // Reject absolute-ish segments and empty path components
        if (strstr(ref_name, "//") != nullptr) return false;
    } else {
        // HEAD is a single file under .git — never treat as multi-segment path escape
    }

    // Require a full 40-char hex SHA (or all-zero for unborn/special cases callers may use)
    size_t sha_len = strlen(sha);
    if (sha_len != Git::SHA1_HEX_SIZE) return false;
    for (size_t i = 0; i < sha_len; i++) {
        char c = sha[i];
        bool hex = (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F');
        if (!hex) return false;
    }

    wchar_t git_dir_wide[Git::MAX_PATH_LEN];
    utf8_to_wide_n(repo->git_dir, git_dir_wide, Git::MAX_PATH_LEN);

    // Build ref path
    wchar_t ref_path[Git::MAX_PATH_LEN];
    wcscpy_s(ref_path, git_dir_wide);
    wcscat_s(ref_path, L"\\");

    wchar_t ref_name_wide[Git::MAX_REF_NAME];
    utf8_to_wide_n(ref_name, ref_name_wide, Git::MAX_REF_NAME);

    // Convert forward slashes to backslashes
    for (wchar_t* p = ref_name_wide; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }
    wcscat_s(ref_path, ref_name_wide);

    // Ensure parent directories exist
    wchar_t parent_dir[Git::MAX_PATH_LEN];
    wcscpy_s(parent_dir, ref_path);
    wchar_t* last_slash = wcsrchr(parent_dir, L'\\');
    if (last_slash) {
        *last_slash = L'\0';

        // Create parent directories
        wchar_t create_path[Git::MAX_PATH_LEN];
        wcscpy_s(create_path, git_dir_wide);
        wchar_t* segment = parent_dir + wcslen(git_dir_wide);
        if (*segment == L'\\') segment++;

        while (*segment) {
            wchar_t* next_slash = wcschr(segment, L'\\');
            if (next_slash) {
                *next_slash = L'\0';
                wcscat_s(create_path, L"\\");
                wcscat_s(create_path, segment);
                ensure_directory(create_path);
                *next_slash = L'\\';
                segment = next_slash + 1;
            } else {
                wcscat_s(create_path, L"\\");
                wcscat_s(create_path, segment);
                ensure_directory(create_path);
                break;
            }
        }
    }

    // Write SHA + newline to ref file
    char content[Git::SHA1_HEX_SIZE + 2];
    snprintf(content, sizeof(content), "%s\n", sha);

    return write_file_atomic(ref_path, content, strlen(content));
}

